 151→            batch_size.min(remaining).max(1)
 152→        } else {
 153→            batch_size
 154→        };
 155→
 156→        let result = emu.run_batch(this_batch);
 157→        total_instructions += result.instructions_run;
 158→
 159→        // Check for LED changes
 160→        let led = emu.get_led();
 161→        if led != prev_led {
 162→            print_leds(led);
 163→            prev_led = led;
 164→        }
 165→
 166→        // Print any new UART output
 167→        let output = emu.get_uart_output();
 168→        if output.len() > prev_uart_len {
 169→            let new_chars = &output[prev_uart_len..];
 170→            for ch in new_chars.chars() {
 171→                if ch == '\n' {
 172→                    println!("[UART TX @ {}] '\\n'", total_instructions);
 173→                } else {
 174→                    println!("[UART TX @ {}] '{}'  (0x{:02X})", total_instructions, ch, ch as u8);
 175→                }
 176→            }
 177→            prev_uart_len = output.len();
 178→        }
 179→
 180→        // Feed next UART input character when previous was consumed (FIFO drain)
 181→        // Only send when RX ready bit (bit 0 of status register) is clear,
 182→        // meaning the program has read the previous byte.
 183→        if uart_input_pos < uart_input.len() {
 184→            let uart_status = emu.read_byte(0xFF0101);
 185→            if uart_status & 0x01 == 0 {
 186→                let ch = uart_input[uart_input_pos];
 187→                emu.send_uart_byte(ch);
 188→                if ch == b'!' {
 189→                    println!("[UART RX] '!'  (0x21) — halt signal");
 190→                } else if ch == b'\n' {
 191→                    println!("[UART RX] '\\n'");
 192→                } else {
 193→                    println!("[UART RX] '{}'  (0x{:02X})", ch as char, ch);
 194→                }
 195→                uart_input_pos += 1;
 196→            }
 197→        }
 198→
 199→        if result.instructions_run == 0 {
 200→            break; // halted or paused
 201→        }
 202→
 203→        if speed > 0 {
 204→            let elapsed = batch_start.elapsed();
 205→            if elapsed < batch_duration {
 206→                thread::sleep(batch_duration - elapsed);
 207→            }
 208→            batch_start = Instant::now();
 209→        }
 210→    }
 211→
 212→    total_instructions
 213→}
