 215→/// Load assembled bytes into emulator at their correct addresses
 216→fn load_assembled(emu: &mut EmulatorCore, result: &cor24_emulator::assembler::AssemblyResult) {
 217→    for line in &result.lines {
 218→        if !line.bytes.is_empty() {
 219→            for (i, &b) in line.bytes.iter().enumerate() {
 220→                emu.write_byte(line.address + i as u32, b);
 221→            }
 222→        }
 223→    }
 224→}
