 232→        mov     fp, sp
 233→        add     sp, -3
 234→
 235→        la      r1, -65536
 236→        lc      r0, 0
 237→        sw      r0, 0(fp)
 238→
 239→main_loop:
 240→        lw      r0, 0(fp)
 241→        sb      r0, 0(r1)
 242→
 243→        la      r2, 15000
 244→delay:
 245→        lc      r0, 1
 246→        sub     r2, r0
 247→        brt     delay
 248→
 249→        lw      r0, 0(fp)
 250→        lc      r2, 1
 251→        add     r0, r2
 252→        sw      r0, 0(fp)
 253→
 254→        bra     main_loop
 255→"#;
