 257→struct CliArgs {
 258→    command: String,
 259→    speed: u64,
 260→    time_limit: f64,
 261→    max_instructions: i64,
 262→    file: Option<String>,
 263→    dump: bool,
 264→    entry: Option<String>,           // entry point label
 265→    uart_input: Vec<u8>,             // characters to send to UART RX
 266→    trace: usize,                    // number of trace entries to dump (0 = off)
 267→    step: bool,                      // step mode: print each instruction
 268→    uart_never_ready: bool,          // UART TX never becomes ready (test polling)
 269→    terminal: bool,                  // bridge stdin/stdout to UART
 270→    echo: bool,                      // echo stdin to stdout in terminal mode
 271→    stack_kb: u32,                   // stack size in KB (3 or 8)
 272→}
 273→
 274→fn parse_args() -> CliArgs {
 275→    let args: Vec<String> = env::args().collect();
 276→    let mut cli = CliArgs {
 277→        command: String::new(),
 278→        speed: DEFAULT_SPEED,
 279→        time_limit: DEFAULT_TIME_LIMIT,
 280→        max_instructions: -1,
 281→        file: None,
 282→        dump: false,
 283→        entry: None,
 284→        uart_input: Vec::new(),
 285→        trace: 0,
 286→        step: false,
 287→        uart_never_ready: false,
 288→        terminal: false,
 289→        echo: false,
 290→        stack_kb: 3,
 291→    };
 292→
 293→    let mut i = 1;
 294→    while i < args.len() {
 295→        match args[i].as_str() {
 296→            "--demo" => cli.command = "demo".to_string(),
 297→            "--run" => {
 298→                cli.command = "run".to_string();
 299→                if i + 1 < args.len() && !args[i + 1].starts_with('-') {
 300→                    cli.file = Some(args[i + 1].clone());
 301→                    i += 1;
 302→                }
 303→            }
 304→            "--assemble" => {
 305→                cli.command = "assemble".to_string();
 306→            }
 307→            "--speed" | "-s" => {
 308→                if i + 1 < args.len() {
 309→                    cli.speed = args[i + 1].parse().unwrap_or(DEFAULT_SPEED);
 310→                    i += 1;
 311→                }
 312→            }
 313→            "--time" | "-t" => {
 314→                if i + 1 < args.len() {
 315→                    cli.time_limit = args[i + 1].parse().unwrap_or(DEFAULT_TIME_LIMIT);
 316→                    i += 1;
 317→                }
 318→            }
 319→            "--dump" => {
 320→                cli.dump = true;
 321→            }
 322→            "--max-instructions" | "-n" => {
 323→                if i + 1 < args.len() {
 324→                    cli.max_instructions = args[i + 1].parse().unwrap_or(-1);
 325→                    i += 1;
 326→                }
 327→            }
 328→            "--uart-input" | "-u" => {
 329→                if i + 1 < args.len() {
 330→                    // Parse escape sequences: \n, \x21, etc.
 331→                    let s = &args[i + 1];
 332→                    let mut bytes = Vec::new();
 333→                    let mut chars = s.chars().peekable();
 334→                    while let Some(ch) = chars.next() {
 335→                        if ch == '\\' {
 336→                            match chars.next() {
 337→                                Some('n') => bytes.push(b'\n'),
 338→                                Some('r') => bytes.push(b'\r'),
 339→                                Some('\\') => bytes.push(b'\\'),
 340→                                Some('x') => {
 341→                                    let hi = chars.next().unwrap_or('0');
 342→                                    let lo = chars.next().unwrap_or('0');
 343→                                    let hex = format!("{}{}", hi, lo);
 344→                                    bytes.push(u8::from_str_radix(&hex, 16).unwrap_or(0));
 345→                                }
 346→                                Some(c) => { bytes.push(b'\\'); bytes.push(c as u8); }
 347→                                None => bytes.push(b'\\'),
 348→                            }
 349→                        } else {
 350→                            bytes.push(ch as u8);
 351→                        }
 352→                    }
 353→                    cli.uart_input = bytes;
 354→                    i += 1;
 355→                }
 356→            }
 357→            "--entry" | "-e" => {
 358→                if i + 1 < args.len() {
 359→                    cli.entry = Some(args[i + 1].clone());
 360→                    i += 1;
 361→                }
 362→            }
 363→            "--trace" => {
 364→                if i + 1 < args.len() {
 365→                    cli.trace = args[i + 1].parse().unwrap_or(50);
 366→                    i += 1;
 367→                } else {
 368→                    cli.trace = 50;
 369→                }
 370→            }
 371→            "--step" => {
 372→                cli.step = true;
 373→            }
 374→            "--uart-never-ready" => {
 375→                cli.uart_never_ready = true;
 376→            }
 377→            "--terminal" => {
 378→                cli.terminal = true;
 379→            }
 380→            "--echo" => {
 381→                cli.echo = true;
 382→            }
 383→            "--stack-kilobytes" => {
 384→                if i + 1 < args.len() {
 385→                    match args[i + 1].parse::<u32>() {
 386→                        Ok(3) => cli.stack_kb = 3,
 387→                        Ok(8) => cli.stack_kb = 8,
 388→                        _ => {
 389→                            eprintln!("Error: --stack-kilobytes must be 3 or 8");
 390→                            std::process::exit(1);
 391→                        }
 392→                    }
 393→                    i += 1;
 394→                }
 395→            }
 396→            _ => {
 397→                if cli.command.is_empty() && !args[i].starts_with('-') {
 398→                    cli.file = Some(args[i].clone());
 399→                }
 400→            }
 401→        }
 402→        i += 1;
 403→    }
 404→
 405→    cli
 406→}
