 409→/// Print one row of 16 bytes in hex + ASCII
 410→fn print_hex_row(emu: &EmulatorCore, addr: u32) {
 411→    print!("  {:06X}:", addr);
 412→    for j in 0..16u32 {
 413→        print!(" {:02X}", emu.read_byte(addr + j));
 414→    }
 415→    print!("  |");
 416→    for j in 0..16u32 {
 417→        let b = emu.read_byte(addr + j);
 418→        if (0x20..=0x7E).contains(&b) {
 419→            print!("{}", b as char);
 420→        } else {
 421→            print!(".");
 422→        }
 423→    }
 424→    println!("|");
 425→}
 426→
 427→/// Check if a 16-byte row is all zero
 428→fn row_is_zero(emu: &EmulatorCore, addr: u32) -> bool {
 429→    for j in 0..16u32 {
 430→        if emu.read_byte(addr + j) != 0 {
 431→            return false;
 432→        }
 433→    }
 434→    true
 435→}
 436→
 437→/// Dump a memory region, collapsing runs of zero rows.
 438→/// Shows non-zero rows verbatim; consecutive zero rows are summarized.
 439→fn dump_memory_region(emu: &EmulatorCore, start: u32, end: u32) {
 440→    let mut addr = start & !0xF; // align to 16
 441→    while addr <= end {
 442→        if row_is_zero(emu, addr) {
 443→            // Count consecutive zero rows
 444→            let zero_start = addr;
 445→            while addr <= end && row_is_zero(emu, addr) {
 446→                addr += 16;
 447→            }
 448→            let zero_bytes = addr - zero_start;
 449→            if zero_bytes <= 16 {
 450→                // Single zero row — just print it
 451→                print_hex_row(emu, zero_start);
 452→            } else {
 453→                println!("  {:06X}..{:06X}: {} bytes all zero", zero_start, addr - 1, zero_bytes);
 454→            }
 455→        } else {
 456→            print_hex_row(emu, addr);
 457→            addr += 16;
 458→        }
 459→    }
 460→}
