 462→/// Print I/O state in a human-readable format
 463→fn print_io_state(emu: &EmulatorCore) {
 464→    let snap = emu.snapshot();
 465→    println!("\n=== I/O FF0000-FFFFFF (64 KB, memory-mapped peripherals) ===");
 466→
 467→    // LED/Switch at 0xFF0000
 468→    // Note: read_byte(0xFF0000) returns switch state; LED state is separate
 469→    let led = snap.led;
 470→    let btn = snap.button;
 471→    print!("  FF0000 LED:  0x{:02X}  [", led);
 472→    for i in (0..8).rev() {
 473→        if (led >> i) & 1 == 1 { print!("*"); } else { print!("."); }
 474→    }
 475→    print!("]  BTN S2: ");
 476→    // button field: normally high (1=released), 0=pressed
 477→    println!("{}", if btn & 1 == 0 { "PRESSED" } else { "released" });
 478→
 479→    // Interrupt enable at 0xFF0010
 480→    let ie = emu.read_byte(0xFF0010);
 481→    println!("  FF0010 IntEn:  0x{:02X}  UART RX IRQ: {}", ie, if ie & 1 == 1 { "enabled" } else { "disabled" });
 482→
 483→    // UART
 484→    let uart_stat = emu.read_byte(0xFF0101);
 485→    println!("  FF0100 UART:   status=0x{:02X}  RX ready: {}  CTS: {}  TX busy: {}",
 486→             uart_stat,
 487→             if uart_stat & 1 == 1 { "yes" } else { "no" },
 488→             if uart_stat & 2 == 2 { "yes" } else { "no" },
 489→             if uart_stat & 0x80 == 0x80 { "yes" } else { "no" });
 490→
 491→    let uart_out = emu.get_uart_output();
 492→    if !uart_out.is_empty() {
 493→        let escaped: String = uart_out.chars().map(|c| {
 494→            if c == '\n' { "\\n".to_string() }
 495→            else if c == '\r' { "\\r".to_string() }
 496→            else { c.to_string() }
 497→        }).collect();
 498→        println!("  UART TX log:   \"{}\"", escaped);
 499→    }
 500→}
 501→
 502→/// Print register and full memory dump
 503→///
 504→/// COR24 24-bit address space:
 505→///   000000-0FFFFF  SRAM (1 MB) — code at low addresses, data/globals above
 506→///   100000-FDFFFF  Unmapped (~14 MB gap, reads 0, writes ignored)
 507→///   FE0000-FEDDFF  Unmapped (below EBR)
 508→///   FEE000-FEFFFF  EBR (8 KB embedded block RAM) — stack (SP init = FEEC00)
 509→///   FF0000-FFFFFF  I/O (64 KB, 4 registers mapped, rest reads 0)
 510→fn print_dump(emu: &EmulatorCore) {
 511→    let snap = emu.snapshot();
 512→    println!("\n=== Registers ===");
 513→    println!("  PC:  0x{:06X}    C: {}", snap.pc, if snap.c { "1" } else { "0" });
 514→    println!("  r0:  0x{:06X}  ({:8})", snap.regs[0], snap.regs[0]);
 515→    println!("  r1:  0x{:06X}  ({:8})", snap.regs[1], snap.regs[1]);
 516→    println!("  r2:  0x{:06X}  ({:8})", snap.regs[2], snap.regs[2]);
 517→    println!("  fp:  0x{:06X}", snap.regs[3]);
 518→    println!("  sp:  0x{:06X}", snap.regs[4]);
 519→    println!("\n=== Emulator ===");
 520→    println!("  Instructions: {}", snap.instructions);
 521→    println!("  Halted: {}", snap.halted);
 522→
 523→    // --- Region 1: SRAM (000000-0FFFFF) ---
 524→    let sram = emu.sram();
 525→    let sram_end = sram.iter().rposition(|&b| b != 0)
 526→        .map(|pos| ((pos as u32) | 0xF) + 1)
 527→        .unwrap_or(0);
 528→    println!("\n=== SRAM 000000-0FFFFF (1 MB) ===");
 529→    if sram_end > 0 {
 530→        dump_memory_region(emu, 0x000000, sram_end - 1);
 531→        if sram_end < 0x100000 {
 532→            println!("  {:06X}..0FFFFF: {} bytes all zero",
 533→                     sram_end, 0x100000 - sram_end);
 534→        }
 535→    } else {
 536→        println!("  000000..0FFFFF: 1048576 bytes all zero");
 537→    }
 538→
 539→    // --- Region 2: Unmapped gap ---
 540→    println!("\n=== Unmapped 100000-FEDDFF (14.9 MB, not installed) ===");
 541→
 542→    // --- Region 3: EBR / Stack (FEE000-FEFFFF) ---
 543→    println!("\n=== EBR FEE000-FEFFFF (8 KB, stack) ===");
 544→    let ebr = emu.ebr();
 545→    if ebr.iter().any(|&b| b != 0) {
 546→        dump_memory_region(emu, 0xFEE000, 0xFEFFFF);
 547→    } else {
 548→        println!("  FEE000..FEFFFF: 8192 bytes all zero");
 549→    }
 550→
 551→    // --- Region 4: I/O (FF0000-FFFFFF) ---
 552→    print_io_state(emu);
 553→}
