 555→/// Run in step mode: execute one instruction at a time, printing each.
 556→/// Stops on halt, max_instructions limit, or loop detection.
 557→fn run_step_mode(emu: &mut EmulatorCore, max_instructions: i64, uart_input: &[u8]) {
 558→    let mut uart_pos = 0usize;
 559→    let mut prev_uart_len = 0usize;
 560→    let max = if max_instructions < 0 { 10_000 } else { max_instructions as u64 };
 561→
 562→    println!("{:>5} {:>8}  {:<24}  {}", "#", "PC", "Instruction", "Changes");
 563→    println!("{}", "-".repeat(80));
 564→
 565→    for n in 0..max {
 566→        // Feed UART input when previous byte consumed (FIFO drain)
 567→        if uart_pos < uart_input.len() {
 568→            let uart_status = emu.read_byte(0xFF0101);
 569→            if uart_status & 0x01 == 0 {
 570→                let ch = uart_input[uart_pos];
 571→                emu.send_uart_byte(ch);
 572→                println!("  --- UART RX: 0x{:02X} ('{}') ---",
 573→                    ch, if (0x20..=0x7E).contains(&ch) { ch as char } else { '.' });
 574→                uart_pos += 1;
 575→            }
 576→        }
 577→
 578→        let result = emu.step();
 579→
 580→        // Print the trace entry for this instruction
 581→        let trace = emu.trace();
 582→        if let Some(entry) = trace.last_n(1).first() {
 583→            println!("{}", entry);
 584→        }
 585→
 586→        // Print any new UART output
 587→        let output = emu.get_uart_output();
 588→        if output.len() > prev_uart_len {
 589→            let new = &output[prev_uart_len..];
 590→            for ch in new.chars() {
 591→                if ch == '\n' {
 592→                    println!("  >>> UART TX: '\\n'");
 593→                } else {
 594→                    println!("  >>> UART TX: '{}'  (0x{:02X})", ch, ch as u8);
 595→                }
 596→            }
 597→            prev_uart_len = output.len();
 598→        }
 599→
 600→        if result.instructions_run == 0 {
 601→            println!("\n--- Halted after {} instructions ---", n);
 602→            break;
 603→        }
 604→    }
 605→
 606→    let uart = emu.get_uart_output();
 607→    if !uart.is_empty() {
 608→        println!("\nUART output: {}", uart);
 609→    }
 610→    println!("\nExecuted {} instructions", emu.instructions_count());
 611→    if emu.is_halted() {
 612→        println!("CPU halted (self-branch detected)");
 613→    }
 614→}
 615→
 616→// --- Terminal mode (raw termios) ---
 617→
 618→/// RAII guard that restores terminal settings on drop.
 619→struct TermiosGuard {
 620→    fd: libc::c_int,
 621→    original: libc::termios,
 622→}
 623→
 624→impl Drop for TermiosGuard {
 625→    fn drop(&mut self) {
 626→        unsafe { libc::tcsetattr(self.fd, libc::TCSAFLUSH, &self.original); }
 627→    }
 628→}
 629→
 630→/// Put stdin into raw mode (character-at-a-time, no echo, no signals).
 631→/// Returns a guard that restores the original settings on drop.
 632→fn set_raw_mode() -> Result<TermiosGuard, String> {
 633→    unsafe {
 634→        let fd = libc::STDIN_FILENO;
 635→        let mut original: libc::termios = std::mem::zeroed();
 636→        if libc::tcgetattr(fd, &mut original) != 0 {
 637→            return Err("tcgetattr failed".to_string());
 638→        }
 639→        let mut raw = original;
 640→        raw.c_lflag &= !(libc::ICANON | libc::ECHO | libc::ISIG);
 641→        raw.c_iflag &= !(libc::IXON | libc::ICRNL);
 642→        raw.c_cc[libc::VMIN] = 0;
 643→        raw.c_cc[libc::VTIME] = 0;
 644→        if libc::tcsetattr(fd, libc::TCSAFLUSH, &raw) != 0 {
 645→            return Err("tcsetattr failed".to_string());
 646→        }
 647→        Ok(TermiosGuard { fd, original })
 648→    }
 649→}
 650→
 651→/// Run the emulator in terminal mode: stdin→UART RX, UART TX→stdout.
 652→fn run_terminal_mode(emu: &mut EmulatorCore, speed: u64, time_limit: f64, max_instructions: i64, echo: bool) -> u64 {
 653→    let is_tty = unsafe { libc::isatty(libc::STDIN_FILENO) } != 0;
 654→
 655→    let _guard = if is_tty {
 656→        match set_raw_mode() {
 657→            Ok(g) => {
 658→                // Also install a panic hook that restores terminal
 659→                let orig = g.original;
 660→                let prev_hook = std::panic::take_hook();
 661→                std::panic::set_hook(Box::new(move |info| {
 662→                    unsafe { libc::tcsetattr(libc::STDIN_FILENO, libc::TCSAFLUSH, &orig); }
 663→                    prev_hook(info);
 664→                }));
 665→                Some(g)
 666→            }
 667→            Err(e) => {
 668→                eprintln!("Warning: could not set raw mode: {}", e);
 669→                None
 670→            }
 671→        }
 672→    } else {
 673→        None
 674→    };
 675→
 676→    if is_tty {
 677→        // Use \r\n since we're in raw mode (no output processing)
 678→        eprint!("[cor24-run terminal mode \u{2014} Ctrl-] to exit]\r\n");
 679→    }
 680→
 681→    let batch_size: u64 = if speed == 0 { 10_000 } else { (speed / 100).max(100) };
 682→    let batch_duration = if speed == 0 {
 683→        Duration::ZERO
 684→    } else {
 685→        Duration::from_secs_f64(batch_size as f64 / speed as f64)
 686→    };
 687→
 688→    let time_limit_duration = if time_limit <= 0.0 {
 689→        Duration::from_secs(3600) // 1 hour default for terminal mode
 690→    } else {
 691→        Duration::from_secs_f64(time_limit)
 692→    };
 693→
 694→    let start = Instant::now();
 695→    let mut total_instructions: u64 = 0;
 696→    let mut batch_start = Instant::now();
 697→    let mut prev_uart_len = 0usize;
 698→    let mut stdin_buf: VecDeque<u8> = VecDeque::new();
 699→    let mut read_buf = [0u8; 256];
 700→    let stdin_fd = libc::STDIN_FILENO;
 701→    let mut stdout = std::io::stdout();
 702→    let mut stdin_eof = false;
 703→
 704→    emu.resume();
 705→
 706→    loop {
 707→        if start.elapsed() >= time_limit_duration {
 708→            break;
 709→        }
 710→        if max_instructions >= 0 && total_instructions >= max_instructions as u64 {
 711→            break;
 712→        }
 713→
 714→        let this_batch = if max_instructions >= 0 {
 715→            let remaining = (max_instructions as u64).saturating_sub(total_instructions);
 716→            batch_size.min(remaining).max(1)
 717→        } else {
 718→            batch_size
 719→        };
 720→
 721→        let result = emu.run_batch(this_batch);
 722→        total_instructions += result.instructions_run;
 723→
 724→        // TX: flush new UART output to stdout as raw bytes
 725→        let output = emu.get_uart_output();
 726→        if output.len() > prev_uart_len {
 727→            let new_bytes = &output.as_bytes()[prev_uart_len..];
 728→            if is_tty {
 729→                // In raw mode, translate \n to \r\n for proper terminal display
 730→                for &b in new_bytes {
 731→                    if b == b'\n' {
 732→                        let _ = stdout.write_all(b"\r\n");
 733→                    } else {
 734→                        let _ = stdout.write_all(&[b]);
 735→                    }
 736→                }
 737→            } else {
 738→                let _ = stdout.write_all(new_bytes);
 739→            }
 740→            let _ = stdout.flush();
 741→            prev_uart_len = output.len();
 742→        }
 743→
 744→        // RX: non-blocking read from stdin
 745→        if !stdin_eof {
 746→            let n = unsafe {
 747→                libc::read(stdin_fd, read_buf.as_mut_ptr() as *mut libc::c_void, read_buf.len())
 748→            };
 749→            if n > 0 {
 750→                let mut did_echo = false;
 751→                for &b in &read_buf[..n as usize] {
 752→                    if b == 0x1D {
 753→                        // Ctrl-] — exit
 754→                        if is_tty {
 755→                            eprint!("\r\n[cor24-run exited]\r\n");
 756→                        }
 757→                        return total_instructions;
 758→                    }
 759→                    if stdin_buf.len() < 4096 {
 760→                        stdin_buf.push_back(b);
 761→                    }
 762→                    if echo {
 763→                        match b {
 764→                            b'\r' | b'\n' => { let _ = stdout.write_all(b"\r\n"); }
 765→                            0x08 | 0x7F => { let _ = stdout.write_all(b"\x08 \x08"); }
 766→                            0x20..=0x7E => { let _ = stdout.write_all(&[b]); }
 767→                            _ => {} // don't echo control characters
 768→                        }
 769→                        did_echo = true;
 770→                    }
 771→                }
 772→                if did_echo {
 773→                    let _ = stdout.flush();
 774→                }
 775→            } else if n == 0 && !is_tty {
 776→                // EOF on piped stdin
 777→                stdin_eof = true;
 778→            }
 779→        }
 780→
 781→        // Feed buffered input to UART when ready
 782→        if !stdin_buf.is_empty() {
 783→            let status = emu.read_byte(0xFF0101);
 784→            if status & 0x01 == 0 {
 785→                let ch = stdin_buf.pop_front().unwrap();
 786→                emu.send_uart_byte(ch);
 787→            }
 788→        }
 789→
 790→        if result.instructions_run == 0 {
 791→            if is_tty {
 792→                eprint!("\r\n[CPU halted]\r\n");
 793→            } else {
 794→                eprintln!("\n[CPU halted]");
 795→            }
 796→            break;
 797→        }
 798→
 799→        // Timing synchronization
 800→        if speed > 0 {
 801→            let elapsed = batch_start.elapsed();
 802→            if elapsed < batch_duration {
 803→                thread::sleep(batch_duration - elapsed);
 804→            }
 805→            batch_start = Instant::now();
 806→        }
 807→    }
 808→
 809→    if is_tty && start.elapsed() >= time_limit_duration {
 810→        eprint!("\r\n[time limit reached]\r\n");
 811→    }
 812→
 813→    total_instructions
 814→}
