 816→fn main() {
 817→    let args: Vec<String> = env::args().collect();
 818→
 819→    // Handle -h, --help, -V, --version before parsing other args
 820→    if args.len() < 2 || args.contains(&"-h".to_string()) {
 821→        print_short_help();
 822→        return;
 823→    }
 824→    if args.contains(&"--help".to_string()) {
 825→        print_long_help();
 826→        return;
 827→    }
 828→    if args.contains(&"-V".to_string()) || args.contains(&"--version".to_string()) {
 829→        print_version();
 830→        return;
 831→    }
 832→
 833→    let cli = parse_args();
 834→
 835→    match cli.command.as_str() {
 836→        "demo" => {
 837→            println!("=== COR24 LED Demo ===\n");
 838→            println!("Binary counter 0-255 on LEDs with spin loop delay");
 839→            println!("Speed: {} instructions/sec, Time limit: {}s\n", cli.speed, cli.time_limit);
 840→
 841→            let mut asm = Assembler::new();
 842→            let result = asm.assemble(DEMO_SOURCE);
 843→            if !result.errors.is_empty() {
 844→                eprintln!("Assembly error: {}", result.errors.join("\n"));
 845→                return;
 846→            }
 847→
 848→            println!("Program listing:");
 849→            for line in &result.lines {
 850→                if !line.bytes.is_empty() {
 851→                    let bytes: String = line.bytes.iter().map(|b| format!("{:02X} ", b)).collect();
 852→                    println!("{:04X}: {:14} {}", line.address, bytes.trim(), line.source);
 853→                }
 854→            }
 855→            println!();
 856→
 857→            let mut emu = EmulatorCore::new();
 858→            load_assembled(&mut emu, &result);
 859→
 860→            println!("Running (Ctrl+C to stop)...\n");
 861→            let instructions = run_with_timing(&mut emu, cli.speed, cli.time_limit, cli.max_instructions, &cli.uart_input);
 862→
 863→            println!("\n\nExecuted {} instructions in {:.1}s", instructions, cli.time_limit);
 864→            println!("Effective speed: {:.0} IPS", instructions as f64 / cli.time_limit);
 865→            if cli.dump { print_dump(&emu); }
 866→        }
 867→
 868→        "run" => {
 869→            let filename = match cli.file {
 870→                Some(f) => f,
 871→                None => {
 872→                    eprintln!("Usage: cor24-run --run <file.s>");
 873→                    return;
 874→                }
 875→            };
 876→
 877→            let source = fs::read_to_string(&filename).expect("Cannot read file");
 878→            let mut asm = Assembler::new();
 879→            let result = asm.assemble(&source);
 880→            if !result.errors.is_empty() {
 881→                eprintln!("Assembly errors:");
 882→                for err in &result.errors {
 883→                    eprintln!("  {}", err);
 884→                }
 885→                return;
 886→            }
 887→
 888→            let byte_count: usize = result.lines.iter().map(|l| l.bytes.len()).sum();
 889→            println!("Assembled {} bytes", byte_count);
 890→
 891→            let mut emu = EmulatorCore::new();
 892→            if cli.uart_never_ready {
 893→                emu.set_uart_never_ready(true);
 894→            }
 895→            // Set stack size: 3 KB → SP=0xFEEC00 (default), 8 KB → SP=0xFF0000
 896→            if cli.stack_kb == 8 {
 897→                emu.set_reg(4, 0xFF0000); // SP = top of full EBR window
 898→            }
 899→            load_assembled(&mut emu, &result);
 900→
 901→            if let Some(entry_label) = &cli.entry {
 902→                // Find label address in assembly result
 903→                let mut found = false;
 904→                for line in &result.lines {
 905→                    let src = line.source.trim();
 906→                    if src.ends_with(':') && src.trim_end_matches(':') == entry_label.as_str() {
 907→                        emu.set_pc(line.address);
 908→                        println!("Entry point: {} @ 0x{:06X}", entry_label, line.address);
 909→                        found = true;
 910→                        break;
 911→                    }
 912→                }
 913→                if !found {
 914→                    eprintln!("Warning: entry point '{}' not found, starting at 0x000000", entry_label);
 915→                }
 916→            }
 917→
 918→            if cli.echo && !cli.terminal {
 919→                eprintln!("Error: --echo requires --terminal");
 920→                return;
 921→            }
 922→
 923→            if cli.terminal {
 924→                // Validate incompatible flags
 925→                if !cli.uart_input.is_empty() {
 926→                    eprintln!("Error: --terminal and --uart-input are incompatible");
 927→                    return;
 928→                }
 929→                if cli.step {
 930→                    eprintln!("Error: --terminal and --step are incompatible");
 931→                    return;
 932→                }
 933→
 934→                let speed = if cli.speed == DEFAULT_SPEED { 0 } else { cli.speed };
 935→                let time_limit = if cli.time_limit == DEFAULT_TIME_LIMIT { 0.0 } else { cli.time_limit };
 936→
 937→                let instructions = run_terminal_mode(&mut emu, speed, time_limit, cli.max_instructions, cli.echo);
 938→
 939→                eprintln!("Executed {} instructions", instructions);
 940→                if cli.trace > 0 {
 941→                    print!("{}", emu.trace().format_last(cli.trace));
 942→                }
 943→                if cli.dump { print_dump(&emu); }
 944→                return;
 945→            }
 946→
 947→            println!("Running (speed: {} IPS, time limit: {}s)...\n",
 948→                     if cli.speed == 0 { "max".to_string() } else { cli.speed.to_string() },
 949→                     cli.time_limit);
 950→
 951→            if cli.step {
 952→                // Step mode: execute one instruction at a time, printing each
 953→                run_step_mode(&mut emu, cli.max_instructions, &cli.uart_input);
 954→            } else {
 955→                let instructions = run_with_timing(&mut emu, cli.speed, cli.time_limit, cli.max_instructions, &cli.uart_input);
 956→
 957→                // Print UART output if any
 958→                let uart = emu.get_uart_output();
 959→                if !uart.is_empty() {
 960→                    println!("\nUART output: {}", uart);
